const BMODEL_FULLY_CLIPPED = 0x10; // returned by checkBBox if the box is trivially outside the frustum
const CLIP_EPSILON = 0.001;         // avoid z-fighting at brush edges
const BACKFACE_EPSILON = 0.01;      // cull polys facing just past perpendicular

function R_BmodelCheckBBox(node: BspNode): number {
  for (let i = 0; i < 4; i++) {
    if (dotProduct(node.mins, frustum[i].normal) - frustum[i].dist > 0) continue;
    if (dotProduct(node.maxs, frustum[i].normal) - frustum[i].dist > 0) continue;
    return BMODEL_FULLY_CLIPPED;
  }
  return 0;
}
